class Solution {
public:
    bool canIWin(int maxChoosableInteger, int desiredTotal) {
        int total = 0;
        for (int i = 1; total < desiredTotal && i <= maxChoosableInteger; i++) {
            total += i;
        }
        return total >= desiredTotal;
    }
};
